import React, { createContext, useContext, useEffect, useMemo, useReducer, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEYS = {
  token: '@auth_token',
  user: '@auth_user',
};

const AuthContext = createContext(null);

const initialState = {
  isLoading: true,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE':
      return {
        ...state,
        isLoading: false,
        token: action.token ?? null,
        user: action.user ?? null,
      };
    case 'SIGN_IN':
      return {
        ...state,
        token: action.token,
        user: action.user,
      };
    case 'SIGN_OUT':
      return {
        ...state,
        token: null,
        user: null,
      };
    default:
      return state;
  }
}

async function persistAuth(token, user) {
  await AsyncStorage.multiSet([
    [STORAGE_KEYS.token, token],
    [STORAGE_KEYS.user, JSON.stringify(user)],
  ]);
}

async function clearAuth() {
  await AsyncStorage.multiRemove([STORAGE_KEYS.token, STORAGE_KEYS.user]);
}

async function restoreAuth() {
  const [[, token], [, userJson]] = await AsyncStorage.multiGet([STORAGE_KEYS.token, STORAGE_KEYS.user]);
  return {
    token: token ?? null,
    user: userJson ? JSON.parse(userJson) : null,
  };
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        const { token, user } = await restoreAuth();
        if (mounted) dispatch({ type: 'RESTORE', token, user });
      } catch (e) {
        if (mounted) dispatch({ type: 'RESTORE', token: null, user: null });
      }
    })();

    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(
    () => ({
      isLoading: state.isLoading,
      token: state.token,
      user: state.user,
      signIn: async ({ token, user }) => {
        await persistAuth(token, user);
        dispatch({ type: 'SIGN_IN', token, user });
      },
      signOut: async () => {
        await clearAuth();
        dispatch({ type: 'SIGN_OUT' });
      },
    }),
    [state.isLoading, state.token, state.user]
  );

  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

function LoadingScreen() {
  return (
    <SafeAreaView style={styles.center}>
      <ActivityIndicator size="large" />
      <Text style={styles.text}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const handleLogin = async () => {
    if (!email.trim() || !password.trim()) {
      Alert.alert('Missing info', 'Please enter email and password.');
      return;
    }

    setSubmitting(true);
    try {
      const response = await fakeAuthApi(email.trim(), password);
      await signIn({ token: response.token, user: response.user });
    } catch (e) {
      Alert.alert('Login failed', e?.message || 'Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Sign In</Text>
      <TextInput
        style={styles.input}
        placeholder="Email"
        autoCapitalize="none"
        keyboardType="email-address"
        value={email}
        onChangeText={setEmail}
      />
      <TextInput
        style={styles.input}
        placeholder="Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />
      <Button title={submitting ? 'Signing in...' : 'Sign In'} onPress={handleLogin} disabled={submitting} />
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Welcome</Text>
      <Text style={styles.text}>Logged in as: {user?.name || user?.email || 'User'}</Text>
      <Text style={styles.text}>User ID: {user?.id || 'N/A'}</Text>
      <View style={styles.spacer} />
      <Button title="Sign Out" onPress={signOut} />
    </SafeAreaView>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

function AuthGate() {
  const { isLoading, token } = useAuth();

  if (isLoading) return <LoadingScreen />;
  return token ? <HomeScreen /> : <LoginScreen />;
}

async function fakeAuthApi(email, password) {
  await new Promise((resolve) => setTimeout(resolve, 800));

  if (password.length < 4) {
    throw new Error('Invalid credentials');
  }

  return {
    token: `mock-token-${Date.now()}`,
    user: {
      id: 'user_123',
      email,
      name: 'Demo User',
    },
  };
}

